190→export function sendRpc(method, params) {
191→	return new Promise((resolve) => {
192→		if (!S.ws || S.ws.readyState !== WebSocket.OPEN) {
193→			resolve({
194→				ok: false,
195→				error: {
196→					code: "UNAVAILABLE",
197→					message: localizedRpcErrorMessage({
198→						code: "UNAVAILABLE",
199→						message: "WebSocket not connected",
200→					}),
201→				},
202→			});
203→			return;
204→		}
205→		var id = nextId();
206→		S.pending[id] = resolve;
207→		S.ws.send(JSON.stringify({ type: "req", id: id, method: method, params: params }));
208→	});
209→}
