211→export function localizedRpcErrorMessage(error) {
212→	if (!error) return t("errors:generic.title");
213→	if (error.code) {
214→		var key = `errors:codes.${error.code}`;
215→		var translated = t(key);
216→		if (translated && translated !== key) {
217→			return translated;
218→		}
219→	}
220→	return error.message || t("errors:generic.title");
221→}
222→
223→export function localizedApiErrorMessage(payload, fallbackMessage) {
224→	if (payload && typeof payload.error === "object") {
225→		return localizedRpcErrorMessage(payload.error);
226→	}
227→	if (payload?.code) {
228→		var key = `errors:codes.${payload.code}`;
229→		var translated = t(key);
230→		if (translated && translated !== key) {
231→			return translated;
232→		}
233→	}
234→	if (payload && typeof payload.error === "string" && payload.error.trim()) {
235→		return payload.error;
236→	}
237→	if (payload && typeof payload.message === "string" && payload.message.trim()) {
238→		return payload.message;
239→	}

